-- O índice em Email SERÁ usado
SELECT * FROM Clientes WHERE Email = 'ana@email.com';

-- O índice em Email NÃO será usado (função na coluna)
SELECT * FROM Clientes WHERE UPPER(Email) = 'ANA@EMAIL.COM';
-- Solução: normalizar ao inserir ou usar índice calculado

-- O índice em DataPedido NÃO será usado (LIKE com % à esquerda)
SELECT * FROM Pedidos WHERE CONVERT(VARCHAR, DataPedido, 103) LIKE '%2024%';
-- Solução: usar BETWEEN com datas
SELECT * FROM Pedidos WHERE DataPedido BETWEEN '2024-01-01' AND '2024-12-31';
